"use client";

import { useEffect, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";

export default function InitialLoader() {
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // Check if the user has already seen the loader in this session
        const hasSeenLoader = sessionStorage.getItem("hasSeenLoader");

        if (hasSeenLoader) {
            setLoading(false);
            return;
        }

        // Otherwise, show it for a short duration
        const timer = setTimeout(() => {
            setLoading(false);
            sessionStorage.setItem("hasSeenLoader", "true");
        }, 2500);

        return () => clearTimeout(timer);
    }, []);

    return (
        <AnimatePresence>
            {loading && (
                <motion.div
                    key="loader"
                    initial={{ opacity: 1 }}
                    exit={{ opacity: 0, scale: 1.05, filter: "blur(10px)" }}
                    transition={{ duration: 0.8, ease: [0.22, 1, 0.36, 1] }}
                    className="fixed inset-0 z-[100] flex flex-col items-center justify-center bg-brand-dark overflow-hidden"
                >
                    {/* Subtle noise background specifically for the loader */}
                    <div className="absolute inset-0 bg-noise opacity-30 select-none pointer-events-none" />

                    <motion.div
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{ duration: 0.8, delay: 0.2 }}
                        className="relative z-10 flex flex-col items-center gap-6"
                    >
                        {/* Elegant Logo Mark */}
                        <motion.div
                            className="w-24 h-24 rounded-full border border-brand-orange/30 flex items-center justify-center relative"
                            animate={{ rotate: 360 }}
                            transition={{ duration: 8, ease: "linear", repeat: Infinity }}
                        >
                            <div className="w-20 h-20 rounded-full border border-brand-orange/50 flex items-center justify-center" />
                            <div className="absolute inset-0 flex items-center justify-center">
                                <span className="font-heading text-brand-orange text-3xl font-bold tracking-widest drop-shadow-glow">PB</span>
                            </div>
                        </motion.div>

                        <div className="flex flex-col items-center gap-2 overflow-hidden">
                            <motion.h1
                                initial={{ y: "100%" }}
                                animate={{ y: 0 }}
                                transition={{ duration: 0.8, delay: 0.5, ease: [0.22, 1, 0.36, 1] }}
                                className="font-heading text-2xl uppercase tracking-[0.3em] font-light text-brand-cream"
                            >
                                Le Pressoir
                            </motion.h1>
                            <motion.span
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                transition={{ duration: 0.5, delay: 1 }}
                                className="font-serif italic text-brand-orange/80 tracking-widest text-sm"
                            >
                                Byzantin
                            </motion.span>
                        </div>

                        {/* Progress line indicator */}
                        <div className="w-32 h-[1px] bg-white/10 mt-4 overflow-hidden relative">
                            <motion.div
                                initial={{ x: "-100%" }}
                                animate={{ x: "100%" }}
                                transition={{ duration: 1.5, ease: "easeInOut", repeat: Infinity }}
                                className="absolute inset-y-0 left-0 w-1/2 bg-gradient-to-r from-transparent via-brand-orange to-transparent"
                            />
                        </div>
                    </motion.div>
                </motion.div>
            )}
        </AnimatePresence>
    );
}
